 3→import (
 4→	"fmt"
 5→	"net"
 6→	"net/http"
 7→	"strings"
 8→)
 9→
10→// IPAllowlist returns middleware that restricts access to the given CIDR ranges.
11→// Requests from IPs not in any CIDR receive 403 Forbidden.
12→func IPAllowlist(cidrs []*net.IPNet) func(http.Handler) http.Handler {
13→	return func(next http.Handler) http.Handler {
14→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
15→			ip := clientIP(r)
16→			if ip == nil || !matchesCIDR(ip, cidrs) {
17→				http.Error(w, "forbidden", http.StatusForbidden)
18→				return
19→			}
20→			next.ServeHTTP(w, r)
21→		})
22→	}
23→}
24→
25→// ParseCIDRs splits a comma-separated list of CIDR strings and parses each one.
26→func ParseCIDRs(raw string) ([]*net.IPNet, error) {
27→	var nets []*net.IPNet
28→	for _, s := range strings.Split(raw, ",") {
29→		s = strings.TrimSpace(s)
30→		if s == "" {
31→			continue
32→		}
33→		_, ipNet, err := net.ParseCIDR(s)
34→		if err != nil {
35→			return nil, fmt.Errorf("middleware: invalid CIDR %q: %w", s, err)
36→		}
37→		nets = append(nets, ipNet)
38→	}
39→	return nets, nil
40→}
41→
42→// clientIP extracts the client IP from the request. It uses RemoteAddr,
43→// which chi's RealIP middleware has already resolved from X-Forwarded-For
44→// or X-Real-IP headers.
45→func clientIP(r *http.Request) net.IP {
46→	host, _, err := net.SplitHostPort(r.RemoteAddr)
47→	if err != nil {
48→		// RemoteAddr might be an IP without port
49→		return net.ParseIP(r.RemoteAddr)
50→	}
51→	return net.ParseIP(host)
52→}
53→
54→func matchesCIDR(ip net.IP, cidrs []*net.IPNet) bool {
55→	for _, cidr := range cidrs {
56→		if cidr.Contains(ip) {
57→			return true
58→		}
59→	}
60→	return false
61→}
