 17→// ExportCSV returns an HTTP handler that streams search results as a CSV file.
 18→// It reads filter, sort, and user-location parameters from the query string,
 19→// builds a search query capped at maxRows, and writes the results as CSV.
 20→func ExportCSV(pool *pgxpool.Pool, reg *search.Registry, maxRows int) http.HandlerFunc {
 21→	return func(w http.ResponseWriter, r *http.Request) {
 22→		q := r.URL.Query()
 23→
 24→		// Parse filters from query param.
 25→		var filters []search.FilterInput
 26→		if filtersParam := q.Get("filters"); filtersParam != "" {
 27→			if err := json.Unmarshal([]byte(filtersParam), &filters); err != nil {
 28→				writeJSONError(w, http.StatusBadRequest,
 29→					fmt.Sprintf("handler: invalid filters JSON: %v", err))
 30→				return
 31→			}
 32→		}
 33→
 34→		req := search.SearchRequest{
 35→			Filters: filters,
 36→			Limit:   maxRows, // request the maximum; BuildExportQuery caps it
 37→		}
 38→
 39→		// Parse sort.
 40→		if sortParam := q.Get("sort"); sortParam != "" {
 41→			req.Sort = &search.SortInput{
 42→				Field:     sortParam,
 43→				Direction: search.SortDirectionAsc,
 44→			}
 45→			if dirParam := q.Get("sortDir"); dirParam == "DESC" {
 46→				req.Sort.Direction = search.SortDirectionDesc
 47→			}
 48→		}
 49→
 50→		// Parse user location.
 51→		latStr, lngStr := q.Get("userLat"), q.Get("userLng")
 52→		if latStr != "" && lngStr != "" {
 53→			lat, errLat := strconv.ParseFloat(latStr, 64)
 54→			lng, errLng := strconv.ParseFloat(lngStr, 64)
 55→			if errLat != nil || errLng != nil {
 56→				writeJSONError(w, http.StatusBadRequest, "handler: invalid userLat/userLng")
 57→				return
 58→			}
 59→			req.UserLocation = &search.UserLocation{
 60→				Latitude:  lat,
 61→				Longitude: lng,
 62→			}
 63→			if stateParam := q.Get("userState"); stateParam != "" {
 64→				req.UserLocation.State = stateParam
 65→			}
 66→		}
 67→
 68→		// Validate the request. Export has no auth; treat as authenticated to
 69→		// allow all fields (access control is handled at the HTTP layer).
 70→		if errs := search.ValidateRequest(reg, req, true); len(errs) > 0 {
 71→			body, _ := json.Marshal(map[string]any{"errors": errs})
 72→			w.Header().Set("Content-Type", "application/json")
 73→			w.WriteHeader(http.StatusBadRequest)
 74→			_, _ = w.Write(body)
 75→			return
 76→		}
 77→
 78→		// Build and execute the export query.
 79→		sqlStr, args, err := search.BuildExportQuery(reg, req, maxRows)
 80→		if err != nil {
 81→			slog.ErrorContext(r.Context(), "handler: build export query", "error", err)
 82→			writeJSONError(w, http.StatusInternalServerError, "handler: failed to build query")
 83→			return
 84→		}
 85→
 86→		rows, err := pool.Query(r.Context(), sqlStr, args...)
 87→		if err != nil {
 88→			slog.ErrorContext(r.Context(), "handler: export query", "error", err)
 89→			writeJSONError(w, http.StatusInternalServerError, "handler: query failed")
 90→			return
 91→		}
 92→		defer rows.Close()
 93→
 94→		// Get exportable field descriptors for CSV columns.
 95→		descriptors := reg.ExportableDescriptors()
 96→
 97→		// Build CSV header row from descriptor labels.
 98→		header := make([]string, len(descriptors))
 99→		for i, d := range descriptors {
100→			header[i] = d.Label
101→		}
102→
103→		// Scan all rows before writing — allows error handling before
104→		// committing to 200 + CSV headers.
105→		type rowData struct {
106→			unitID          string
107→			institutionName string
108→			city            string
109→			state           string
110→			data            json.RawMessage
111→		}
112→		var rowResults []rowData
113→
114→		for rows.Next() {
115→			var (
116→				unitID, instName, city, state string
117→				lat, lng, distance            *float64
118→				myPrice                       *int
119→				data                          json.RawMessage
120→				blendScore                    *float64 // column 10: unused in export but must be scanned
121→			)
122→			if err := rows.Scan(&unitID, &instName, &city, &state,
123→				&lat, &lng, &distance, &myPrice, &data, &blendScore); err != nil {
124→				slog.ErrorContext(r.Context(), "handler: scan export row", "error", err)
125→				writeJSONError(w, http.StatusInternalServerError, "handler: scan failed")
126→				return
127→			}
128→			rowResults = append(rowResults, rowData{
129→				unitID:          unitID,
130→				institutionName: instName,
131→				city:            city,
132→				state:           state,
133→				data:            data,
134→			})
135→		}
136→		if err := rows.Err(); err != nil {
137→			slog.ErrorContext(r.Context(), "handler: export rows iteration", "error", err)
138→			writeJSONError(w, http.StatusInternalServerError, "handler: query iteration failed")
139→			return
140→		}
141→
142→		// Write CSV response.
143→		w.Header().Set("Content-Type", "text/csv; charset=utf-8")
144→		w.Header().Set("Content-Disposition", `attachment; filename="colleges-export.csv"`)
145→
146→		cw := csv.NewWriter(w)
147→		if err := cw.Write(header); err != nil {
148→			slog.ErrorContext(r.Context(), "handler: write CSV header", "error", err)
149→			return
150→		}
151→
152→		record := make([]string, len(descriptors))
153→		for _, row := range rowResults {
154→			for i, d := range descriptors {
155→				record[i] = extractCoreOrJSONB(d, row.unitID, row.institutionName, row.city, row.state, row.data)
156→			}
157→			if err := cw.Write(record); err != nil {
158→				slog.ErrorContext(r.Context(), "handler: write CSV row", "error", err)
159→				return
160→			}
161→		}
162→		// Append data sources citation section.
163→		writeCitationSection(cw, descriptors)
164→
165→		cw.Flush()
166→		if err := cw.Error(); err != nil {
167→			slog.ErrorContext(r.Context(), "handler: flush CSV", "error", err)
168→		}
169→	}
170→}
171→
172→// writeCitationSection appends a "Data Sources" section to the CSV listing each
173→// unique data source referenced by the exported fields.
174→func writeCitationSection(cw *csv.Writer, descriptors []search.FieldDescriptor) {
175→	// Build ID→DataSource lookup.
176→	allSources := search.AllDataSources()
177→	sourceByID := make(map[string]search.DataSource, len(allSources))
178→	for _, ds := range allSources {
179→		sourceByID[ds.ID] = ds
180→	}
181→
182→	// Collect unique sources in stable order (first-seen among descriptors).
183→	seen := make(map[string]bool)
184→	var sources []search.DataSource
185→	for _, d := range descriptors {
186→		if d.DataSourceID == "" || seen[d.DataSourceID] {
187→			continue
188→		}
189→		seen[d.DataSourceID] = true
190→		if ds, ok := sourceByID[d.DataSourceID]; ok {
191→			sources = append(sources, ds)
192→		}
193→	}
194→	if len(sources) == 0 {
195→		return
196→	}
197→
198→	_ = cw.Write([]string{}) // blank separator row
199→	_ = cw.Write([]string{"Data Sources"})
200→	_ = cw.Write([]string{"Source", "Dataset", "URL"})
201→	for _, ds := range sources {
202→		_ = cw.Write([]string{ds.Name, ds.Dataset, ds.URL})
203→	}
204→}
