206→// extractCoreOrJSONB returns the CSV cell value for a descriptor.
207→// Core fields (name, city, state, unit_id) are extracted from scanned columns;
208→// all others are extracted from the data JSONB blob via OutputKey.
209→func extractCoreOrJSONB(d search.FieldDescriptor, unitID, instName, city, state string, data json.RawMessage) string {
210→	switch d.Name {
211→	case "name":
212→		return instName
213→	case "city":
214→		return city
215→	case "state":
216→		return state
217→	case "unit_id":
218→		return unitID
219→	default:
220→		if d.OutputKey == "" {
221→			return ""
222→		}
223→		return extractJSONBValue(data, d.OutputKey)
224→	}
225→}
226→
227→// extractJSONBValue navigates a dot-separated path into a JSON blob and
228→// returns the value as a string. Returns "" for nil, missing, or unparseable.
229→func extractJSONBValue(data json.RawMessage, dotPath string) string {
230→	if len(data) == 0 {
231→		return ""
232→	}
233→	parts := strings.Split(dotPath, ".")
234→	var current any
235→	if err := json.Unmarshal(data, &current); err != nil {
236→		return ""
237→	}
238→	for _, part := range parts {
239→		m, ok := current.(map[string]any)
240→		if !ok {
241→			return ""
242→		}
243→		current, ok = m[part]
244→		if !ok {
245→			return ""
246→		}
247→	}
248→	if current == nil {
249→		return ""
250→	}
251→	return fmt.Sprintf("%v", current)
252→}
