254→// writeJSONError writes a JSON error response with the given status code and message.
255→func writeJSONError(w http.ResponseWriter, status int, message string) {
256→	w.Header().Set("Content-Type", "application/json")
257→	w.WriteHeader(status)
258→	_ = json.NewEncoder(w).Encode(map[string]string{"error": message})
259→}
